import 'package:flutter/material.dart';\nimport 'package:go_router/go_router.dart';\nimport 'package:provider/provider.dart';\nimport 'package:vedanta_trade/features/authentication/presentation/providers/auth_provider.dart';\n\nclass AuthGuard {\n  static Future<bool> checkAuth(BuildContext context) async {\n    final auth = context.read<AuthProvider>();\n    \n    // Check if user is logged in\n    if (!auth.isLoggedIn) {\n      return false;\n    }\n    \n    // Validate session with backend\n    final isValid = await auth.validateSession();\n    if (!isValid) {\n      return false;\n    }\n    \n    return true;\n  }\n  \n  static Future<void> redirectToLogin(BuildContext context) async {\n    await context.read<AuthProvider>().logout(force: true);\n    if (context.mounted) {\n      context.go('/login');\n    }\n  }\n  \n  static String? getInitialRoute(String? userRole) {\n    switch (userRole) {\n      case 'ADMIN':\n        return '/admin';\n      case 'MEDICAL_REP':\n        return '/mr';\n      case 'ACCOUNTANT':\n        return '/accounting';\n      case 'DOCTOR':\n        return '/doctor';\n      case 'STOCKIST':\n        return '/stockist';\n      case 'RETAILER':\n        return '/retailer';\n      default:\n        return '/login';\n    }\n  }\n}\n\nclass ProtectedRoute extends StatelessWidget {\n  final Widget child;\n  final String? requiredRole;\n  final String? fallbackRoute;\n  \n  const ProtectedRoute({\n    super.key,\n    required this.child,\n    this.requiredRole,\n    this.fallbackRoute = '/login',\n  });\n  \n  @override\n  Widget build(BuildContext context) {\n    return Consumer<AuthProvider>(\n      builder: (context, auth, _) {\n        // Show loading while checking auth\n        if (auth.isLoading) {\n          return const Scaffold(\n            body: Center(\n              child: CircularProgressIndicator(),\n            ),\n          );\n        }\n        \n        // Check if user is authenticated\n        if (!auth.isLoggedIn) {\n          WidgetsBinding.instance.addPostFrameCallback((_) {\n            context.go(fallbackRoute!);\n          });\n          return const Scaffold(\n            body: Center(\n              child: Text('Redirecting to login...'),\n            ),\n          );\n        }\n        \n        // Check role-based access if required\n        if (requiredRole != null && auth.userRole != requiredRole) {\n          WidgetsBinding.instance.addPostFrameCallback((_) {\n            context.go('/unauthorized');\n          });\n          return const Scaffold(\n            body: Center(\n              child: Text('Access denied'),\n            ),\n          );\n        }\n        \n        return child;\n      },\n    );\n  }\n}\n\nclass AuthMiddleware {\n  static Future<bool> canAccessRoute(BuildContext context, String route) async {\n    final auth = context.read<AuthProvider>();\n    \n    // Public routes that don't require authentication\n    const publicRoutes = ['/login', '/register', '/forgot-password', '/reset-password'];\n    if (publicRoutes.contains(route)) {\n      return true;\n    }\n    \n    // Check if user is authenticated\n    if (!auth.isLoggedIn) {\n      return false;\n    }\n    \n    // Check role-based access\n    return _checkRoleAccess(auth.userRole, route);\n  }\n  \n  static bool _checkRoleAccess(String? userRole, String route) {\n    switch (userRole) {\n      case 'ADMIN':\n        return _canAdminAccess(route);\n      case 'MEDICAL_REP':\n        return _canMrAccess(route);\n      case 'ACCOUNTANT':\n        return _canAccountantAccess(route);\n      case 'DOCTOR':\n        return _canDoctorAccess(route);\n      case 'STOCKIST':\n        return _canStockistAccess(route);\n      case 'RETAILER':\n        return _canRetailerAccess(route);\n      default:\n        return false;\n    }\n  }\n  \n  static bool _canAdminAccess(String route) {\n    // Admin can access all routes\n    return true;\n  }\n  \n  static bool _canMrAccess(String route) {\n    const allowedRoutes = ['/mr', '/mr/', '/mr/dashboard', '/mr/visits', '/mr/products', '/mr/orders'];\n    return allowedRoutes.any((allowed) => route.startsWith(allowed));\n  }\n  \n  static bool _canAccountantAccess(String route) {\n    const allowedRoutes = ['/accounting', '/accounting/', '/accounting/dashboard', '/accounting/reports', '/accounting/transactions'];\n    return allowedRoutes.any((allowed) => route.startsWith(allowed));\n  }\n  \n  static bool _canDoctorAccess(String route) {\n    const allowedRoutes = ['/doctor', '/doctor/', '/doctor/dashboard', '/doctor/prescriptions', '/doctor/products'];\n    return allowedRoutes.any((allowed) => route.startsWith(allowed));\n  }\n  \n  static bool _canStockistAccess(String route) {\n    const allowedRoutes = ['/stockist', '/stockist/', '/stockist/dashboard', '/stockist/inventory', '/stockist/orders'];\n    return allowedRoutes.any((allowed) => route.startsWith(allowed));\n  }\n  \n  static bool _canRetailerAccess(String route) {\n    const allowedRoutes = ['/retailer', '/retailer/', '/retailer/dashboard', '/retailer/products', '/retailer/orders'];\n    return allowedRoutes.any((allowed) => route.startsWith(allowed));\n  }\n}\n\nclass SessionManager {\n  static void startSessionMonitoring(BuildContext context) {\n    final auth = context.read<AuthProvider>();\n    \n    // Check session every 5 minutes\n    Stream.periodic(const Duration(minutes: 5)).listen((_) async {\n      if (auth.isLoggedIn) {\n        final isValid = await auth.validateSession();\n        if (!isValid && context.mounted) {\n          await AuthGuard.redirectToLogin(context);\n        }\n      }\n    });\n  }\n  \n  static void handleAppLifecycle(BuildContext context, AppLifecycleState state) {\n    final auth = context.read<AuthProvider>();\n    \n    switch (state) {\n      case AppLifecycleState.paused:\n        // App is in background - start timer for auto-logout\n        _startAutoLogoutTimer(context);\n        break;\n      case AppLifecycleState.resumed:\n        // App is back in foreground - cancel auto-logout timer\n        _cancelAutoLogoutTimer();\n        // Validate session\n        if (auth.isLoggedIn) {\n          auth.validateSession();\n        }\n        break;\n      case AppLifecycleState.detached:\n        // App is being closed - cleanup\n        _cancelAutoLogoutTimer();\n        break;\n      default:\n        break;\n    }\n  }\n  \n  static Timer? _autoLogoutTimer;\n  \n  static void _startAutoLogoutTimer(BuildContext context) {\n    _cancelAutoLogoutTimer();\n    \n    // Auto-logout after 30 minutes in background\n    _autoLogoutTimer = Timer(const Duration(minutes: 30), () async {\n      final auth = context.read<AuthProvider>();\n      if (auth.isLoggedIn && context.mounted) {\n        await AuthGuard.redirectToLogin(context);\n      }\n    });\n  }\n  \n  static void _cancelAutoLogoutTimer() {\n    _autoLogoutTimer?.cancel();\n    _autoLogoutTimer = null;\n  }\n}\n\nclass UnauthorizedScreen extends StatelessWidget {\n  const UnauthorizedScreen({super.key});\n  \n  @override\n  Widget build(BuildContext context) {\n    return Scaffold(\n      backgroundColor: const Color(0xFF1A1D2E),\n      body: Center(\n        child: Padding(\n          padding: const EdgeInsets.all(32.0),\n          child: Column(\n            mainAxisAlignment: MainAxisAlignment.center,\n            children: [\n              Container(\n                width: 80, height: 80,\n                decoration: BoxDecoration(\n                  color: Colors.red.withOpacity(0.1),\n                  borderRadius: BorderRadius.circular(40),\n                ),\n                child: const Icon(Icons.block_rounded, size: 40, color: Colors.red),\n              ),\n              const SizedBox(height: 24),\n              const Text(\n                'Access Denied',\n                style: TextStyle(\n                  fontSize: 24,\n                  fontWeight: FontWeight.bold,\n                  color: Colors.white,\n                ),\n              ),\n              const SizedBox(height: 12),\n              const Text(\n                'You don\\'t have permission to access this page.',\n                textAlign: TextAlign.center,\n                style: TextStyle(\n                  fontSize: 16,\n                  color: Colors.white70,\n                ),\n              ),\n              const SizedBox(height: 32),\n              ElevatedButton(\n                onPressed: () => context.go('/'),\n                style: ElevatedButton.styleFrom(\n                  backgroundColor: const Color(0xFF2E7D32),\n                  padding: const EdgeInsets.symmetric(horizontal: 32, vertical: 16),\n                ),\n                child: const Text(\n                  'Go to Dashboard',\n                  style: TextStyle(fontSize: 16, fontWeight: FontWeight.w600),\n                ),\n              ),\n            ],\n          ),\n        ),\n      ),\n    );\n  }\n}
